$ErrorActionPreference = 'Stop'
$ServerHost = '192.168.30.12'
$AgentDir = Join-Path $env:ProgramData 'SmartCenterAgent'
$WorkerPath = Join-Path $AgentDir 'agent_worker.ps1'
$ConfigPath = Join-Path $AgentDir 'agent_config.json'
$TaskName = 'SmartCenterAgent'

New-Item -ItemType Directory -Force -Path $AgentDir | Out-Null
$worker = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(''))
Set-Content -Path $WorkerPath -Value $worker -Encoding UTF8
$agentConfig = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(''))
Set-Content -Path $ConfigPath -Value $agentConfig -Encoding UTF8

$action = New-ScheduledTaskAction -Execute 'powershell.exe' -Argument "-NoProfile -ExecutionPolicy Bypass -File `"$WorkerPath`""
$trigger = New-ScheduledTaskTrigger -AtStartup
$principal = New-ScheduledTaskPrincipal -UserId 'SYSTEM' -LogonType ServiceAccount -RunLevel Highest
$settings = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -StartWhenAvailable

try {
    Unregister-ScheduledTask -TaskName $TaskName -Confirm:$false -ErrorAction SilentlyContinue | Out-Null
} catch {}

Register-ScheduledTask -TaskName $TaskName -Action $action -Trigger $trigger -Principal $principal -Settings $settings | Out-Null
Start-ScheduledTask -TaskName $TaskName
Write-Host 'SmartCenterAgent 已部署并启动'
Write-Host ('服务器地址: http://' + $ServerHost + ':6899')
